#!/usr/bin/env python3
"""Operation Chain Configuration — Defines and validates operation parameters.
Mission profiles, ROE constraints, target specifications."""
import json
import os
import time

class OperationConfig:
    """Operation chain configuration and validation."""

    MISSION_PROFILES = {
        'stealth_recon': {
            'description': 'Low-footprint intelligence gathering',
            'phases': [0, 1, 2, 3, 8],  # CI, Access, SA, Creds, Anti-Forensics
            'persistence': False,
            'c2_type': 'covert',
            'max_duration_hours': 2,
            'roe': {
                'no_write_operations': True,
                'no_lateral_movement': True,
                'no_persistence': True,
                'passive_only': True,
            },
        },
        'full_compromise': {
            'description': 'Complete domain/network takeover',
            'phases': list(range(10)),  # All phases
            'persistence': True,
            'c2_type': 'standard',
            'max_duration_hours': 72,
            'roe': {
                'lateral_movement': True,
                'persistence': True,
                'credential_harvesting': True,
            },
        },
        'smash_and_grab': {
            'description': 'Rapid data theft and exit',
            'phases': [0, 1, 2, 3, 7, 8, 9],  # Skip graph, persist, C2
            'persistence': False,
            'c2_type': None,
            'max_duration_hours': 1,
            'roe': {
                'speed_priority': True,
                'no_persistence': True,
            },
        },
        'infrastructure_attack': {
            'description': 'ICS/OT disruption operation',
            'phases': [0, 1, 2, 5, 6, 7, 8],  # CI, Access, SA, Persist, C2, Obj, AF
            'persistence': True,
            'c2_type': 'covert',
            'max_duration_hours': 48,
            'roe': {
                'ics_target': True,
                'physical_effects': True,
                'safety_systems': False,  # Don't disable safety by default
            },
        },
        'counter_operation': {
            'description': 'Counter-intelligence and adversary disruption',
            'phases': [0, 1, 2, 7, 8],  # CI, Access, SA, Obj (CI), AF
            'persistence': False,
            'c2_type': None,
            'max_duration_hours': 4,
            'roe': {
                'counter_intel_focus': True,
                'implant_neutralization': True,
            },
        },
    }

    def __init__(self, profile='full_compromise', target=None, custom_roe=None):
        self.profile_name = profile
        self.profile = self.MISSION_PROFILES.get(profile, self.MISSION_PROFILES['full_compromise'])
        self.target = target
        self.custom_roe = custom_roe or {}
        self.start_time = time.time()
        self.config_id = os.urandom(8).hex()

    def validate(self):
        """Validate operation configuration."""
        errors = []

        if self.profile_name not in self.MISSION_PROFILES:
            errors.append(f'Unknown profile: {self.profile_name}')

        if not self.target:
            errors.append('No target specified')

        return {'valid': len(errors) == 0, 'errors': errors}

    def get_active_phases(self):
        """Return list of active phase numbers for this profile."""
        return self.profile.get('phases', list(range(10)))

    def get_roe(self):
        """Get Rules of Engagement (ROE) with custom overrides."""
        roe = dict(self.profile.get('roe', {}))
        roe.update(self.custom_roe)
        return roe

    def to_dict(self):
        return {
            'config_id': self.config_id,
            'profile': self.profile_name,
            'description': self.profile['description'],
            'target': self.target,
            'phases': self.get_active_phases(),
            'persistence': self.profile['persistence'],
            'c2_type': self.profile['c2_type'],
            'max_duration_hours': self.profile['max_duration_hours'],
            'roe': self.get_roe(),
        }


def main():
    import argparse
    parser = argparse.ArgumentParser(description='Operation Chain Config')
    parser.add_argument('--profile', default='full_compromise',
                       choices=list(OperationConfig.MISSION_PROFILES.keys()))
    parser.add_argument('--target', required=True)
    parser.add_argument('--list-profiles', action='store_true')
    args = parser.parse_args()

    if args.list_profiles:
        for name, profile in OperationConfig.MISSION_PROFILES.items():
            phases = profile['phases']
            print(f'  {name}: {profile["description"]} ({len(phases)} phases)')
        return

    config = OperationConfig(args.profile, args.target)
    validation = config.validate()
    print(json.dumps(config.to_dict(), indent=2))
    if not validation['valid']:
        print(f'\nErrors: {validation["errors"]}')

if __name__ == '__main__':
    main()
